def max_water_delivery(n, pipes, houses):
    from collections import defaultdict, deque

    sink = n  # super sink node

    capacity = defaultdict(lambda: defaultdict(int))
    graph = defaultdict(set)

    for u, v, c in pipes:
        capacity[u][v] += c
        graph[u].add(v)
        graph[v].add(u)

    for node_id, demand in houses:
        capacity[node_id][sink] += demand
        graph[node_id].add(sink)
        graph[sink].add(node_id)

    def bfs():
        parent = {0: -1}
        queue = deque([0])
        while queue:
            node = queue.popleft()
            for neighbor in graph[node]:
                if neighbor not in parent and capacity[node][neighbor] > 0:
                    parent[neighbor] = node
                    if neighbor == sink:
                        path = []
                        curr = sink
                        while curr != -1:
                            path.append(curr)
                            curr = parent[curr]
                        return path[::-1]
                    queue.append(neighbor)
        return None

    max_flow = 0
    while True:
        path = bfs()
        if path is None:
            break
        flow = float('inf')
        for i in range(len(path) - 1):
            flow = min(flow, capacity[path[i]][path[i + 1]])
        for i in range(len(path) - 1):
            capacity[path[i]][path[i + 1]] -= flow
            capacity[path[i + 1]][path[i]] += flow
        max_flow += flow

    return max_flow

