import unittest

class TestSolution(unittest.TestCase):
    def test_simple_linear(self):
        self.assertEqual(max_water_delivery(3, [(0,1,10),(1,2,5)], [(2,5)]), 5)

    def test_two_paths_one_house(self):
        self.assertEqual(max_water_delivery(4, [(0,1,10),(0,2,10),(1,3,5),(2,3,5)], [(3,15)]), 10)

    def test_multiple_houses(self):
        self.assertEqual(max_water_delivery(4, [(0,1,10),(0,2,8),(1,3,6),(2,3,5)], [(1,3),(3,10)]), 13)

    def test_hidden_no_path_to_house(self):
        self.assertEqual(max_water_delivery(3, [(0,1,10)], [(2,5)]), 0)

    def test_hidden_source_is_house(self):
        self.assertEqual(max_water_delivery(1, [], [(0,10)]), 10)

    def test_hidden_parallel_pipes(self):
        self.assertEqual(max_water_delivery(2, [(0,1,5),(0,1,3)], [(1,10)]), 8)

    def test_hidden_diamond_network(self):
        self.assertEqual(max_water_delivery(4, [(0,1,10),(0,2,10),(1,3,8),(2,3,8)], [(3,20)]), 16)

    def test_hidden_small_pipe_large_demand(self):
        self.assertEqual(max_water_delivery(2, [(0,1,1)], [(1,1000)]), 1)

    def test_hidden_no_houses(self):
        self.assertEqual(max_water_delivery(3, [(0,1,5),(1,2,3)], []), 0)

    def test_hidden_classic_flow(self):
        pipes = [(0,1,16),(0,2,13),(1,2,4),(1,3,12),(2,1,10),(2,4,14),(3,2,9),(3,5,20),(4,3,7),(4,5,4)]
        self.assertEqual(max_water_delivery(6, pipes, [(5,100)]), 23)

    def test_hidden_demand_bottleneck(self):
        # Pipe capacity is 100 but house demand is only 3
        self.assertEqual(max_water_delivery(2, [(0,1,100)], [(1,3)]), 3)

if __name__ == '__main__':
    unittest.main()
